class Solution:
    def findBridges(self, graph, root):
        visited = [False] * len(graph)
        low = [0] * len(graph)
        disc = [0] * len(graph)
        timer = 0

        strongComp = [[] for _ in range(len(graph))]
        edges = [[] for _ in range(len(graph))]

        def dfs(node, parent):
            global timer
            visited[node] = True
            disc[node] = low[node] = timer
            timer += 1
            for neighbor in graph[node]:
                if neighbor == parent:
                    continue
                if visited[neighbor]:
                    low[node] = min(low[node], disc[neighbor])
                else:
                    self.dfs(neighbor, node)
                    low[node] = min(low[node], low[neighbor])
                    if low[neighbor] > disc[node]:
                        edges[node].append(neighbor)

                        # Check for articulation points
                        if parent != -1 and low[neighbor] >= disc[node]:
                            strongComp[node].append(neighbor)

        dfs(root, -1)

        return [edge for edge in edges if len(edge) > 1]

