class Solution {
public:
    vector<int> findBridges(vector<vector<int>>& graph, int root) {
        int n = graph.size();
        vector<bool> visited(n, false);
        vector<int> low(n, 0);
        vector<int> disc(n, 0);
        vector<int> timer(1, 0);

        vector<vector<int>> strongComp(n, vector<int>());
        vector<vector<int>> edges(n, vector<int>());

        function<void(int, int)> dfs = [&](int node, int parent) {
            visited[node] = true;
            disc[node] = low[node] = timer[0];
            timer[0]++;
            for (int neighbor : graph[node]) {
                if (neighbor == parent)
                    continue;

                if (visited[neighbor])
                    low[node] = min(low[node], disc[neighbor]);
                else
                    dfs(neighbor, node);
                    low[node] = min(low[node], low[neighbor]);
                    if (low[neighbor] > disc[node])
                        edges[node].push_back(neighbor);

                        // Check for articulation points
                        if (parent != -1 && low[neighbor] >= disc[node])
                            strongComp[node].push_back(neighbor);
            }
        };

        dfs(root, -1);

        vector<int> result;

        for (int i = 0; i < n; i++)
            if (edges[i].size() > 1)
                result.push_back(i);

        return result;
    }
};

